function x = unitconvert_bp(x, UnitFrom, UnitTo)%UNITCONVERT converts a quantity from one unit to another.%   UNITCONVERT(X, UNITFROM, UNITTO) converts a physical quantity X from UNITFROM to UNITTO.%%   Incompatible units will generate an error.%%   See also UNITS, UNITSCALE.%   $Revision: 1.1 $    $Date: 2002/06/10 04:41:50 $%%   $Log: unitconvert.m,v $%   Revision 1.1  2002/06/10 04:41:50  xg%   Created.%error(nargchk(3, 3, nargin))[sf, bf] = units(UnitFrom);[st, bt] = units(UnitTo);if (~strcmp(bf, bt))    error('Incompatible units.');endx = x * sf / st;